    'dispute_coll_stamp' => '<strong>थोडक्यात:</strong> अनेक मुद्दे किनारी राज्याच्या 200 सागरी मैल क्षेत्रात येतात, किंवा नकाशावर चुकीने मोजले जातात, किंवा शेजाऱ्याच्या दिशेने अधिक सरकवले जातात — तरीही नाइन-डॅश रेषेद्वारे त्यांना वेढले जाते. त्यामुळेच 2016 मधील तटस्थ लवाद न्यायाधिकरण आणि विविध देशांनी याला UNCLOS च्या तुलनेत <strong>अतिप्रसारी समुद्री दावा</strong> मानले.',
